// deepCopy performs a deep copy of a map[string]interface{} using JSON serialization.
func deepCopy(item map[string]interface{}) (map[string]interface{}, error) {
	data, err := json.Marshal(item)
	if err != nil {
		return nil, err
	}
	var copy map[string]interface{}
	err = json.Unmarshal(data, &copy)
	if err != nil {
		return nil, err
	}
	return copy, nil
}

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	// Timeout duration for script execution (adjust as needed)
	const timeout = 5 * time.Second

	for _, item := range items {
		// Create a context with timeout to limit script execution time
		ctx, cancel := context.WithTimeout(context.Background(), timeout)
		defer cancel()

		vm := otto.New()

		// Deep copy the item to prevent script from modifying original
		copiedItem, err := deepCopy(item)
		if err != nil {
			return nil, err
		}

		// Inject the copied item as a global variable named 'item'
		err = vm.Set("item", copiedItem)
		if err != nil {
			return nil, err
		}

		// Run the condition script
		var value otto.Value
		done := make(chan struct{})
		go func() {
			defer close(done)
			var runErr error
			value, runErr = vm.Run(conditionScript)
			if runErr != nil {
				err = runErr
			}
		}()

		select {
		case <-done:
			if err != nil {
				return nil, err
			}
		case <-ctx.Done():
			return nil, ctx.Err() // Return timeout or cancellation error
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item) // Add original item to result, not copied
		}
	}

	return result, nil
}

