import (
	"context"
	"time"

	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	const timeout = 5 * time.Second // Reasonable default timeout to prevent DoS
	var result []map[string]interface{}

	for _, item := range items {
		// Create a context with timeout for this item's script execution
		ctx, cancel := context.WithTimeout(context.Background(), timeout)
		defer cancel() // Ensure resources are freed even if execution fails

		vm := otto.New()

		// Inject current item as global 'item' variable
		err := vm.Set("item", item)
		if err != nil {
			return nil, err
		}

		// Execute the condition script in a goroutine
		var value otto.Value
		var runErr error
		done := make(chan struct{})
		go func() {
			value, runErr = vm.Run(conditionScript)
			close(done)
		}()

		// Wait for either completion or timeout
		select {
		case <-ctx.Done():
			return nil, ctx.Err() // Timeout or cancelled
		case <-done:
			if runErr != nil {
				return nil, runErr
			}
		}

		// Convert script result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

func main() {
	// Example usage
	items := []map[string]interface{}{
		{"id": 1, "active": true},
		{"id": 2, "active": false},
	}
	script := `item.active == true`

	result, err := FilterItems(script, items)
