// deepCopy creates a deep copy of a map[string]interface{} using gob encoding
func deepCopy(item map[string]interface{}) (map[string]interface{}, error) {
	var buf bytes.Buffer
	encoder := gob.NewEncoder(&buf)
	if err := encoder.Encode(item); err != nil {
		return nil, err
	}

	var copied map[string]interface{}
	decoder := gob.NewDecoder(&buf)
	if err := decoder.Decode(&copied); err != nil {
		return nil, err
	}

	return copied, nil
}

