		resChan := make(chan struct {
			value otto.Value
			err   error
		}, 1)

		// Run script in a goroutine to enforce timeout
		go func() {
			value, err := vm.Run(conditionScript)
			resChan <- struct {
				value otto.Value
				err   error
			}{value, err}
		}()

		select {
		case res := <-resChan:
			if res.err != nil {
				return nil, res.err
			}

			// Convert result to boolean using JavaScript truthiness
			boolResult, err := res.value.ToBoolean()
			if err != nil {
				return nil, err
			}

			if boolResult {
				result = append(result, item) // Keep original item
			}
		case <-time.After(timeout):
			return nil, fmt.Errorf("script execution timed out after %v", timeout)
		}
	}

	return result, nil
}

